mapper.select:
SELECT m_motocycle.moto_no , m_motocycle.moto_name , m_motocycle.brand_id , m_motocycle.cylinder , m_motocycle.cooling , m_motocycle.price , m_motocycle.comment , m_brand.brand_name FROM m_motocycle LEFT OUTER JOIN m_brand ON m_motocycle.brand_id = m_brand.brand_id
AND m_motocycle.brand_id = #{brandId}
AND m_motocycle.moto_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY moto_no;

mapper.insert:
  INSERT 
  INTO m_motocycle( 
    moto_no
    , moto_name
    , seat_height
    , cylinder
    , cooling
    , price
    , comment
    , brand_id
    , version
    , ins_dt
) 
VALUES ( 
    #{motoNo}
    , #{motoName}
    , #{seatHeight}
    , #{cylinder}
    , #{cooling}
    , #{price}
    , #{comment}
    , #{brandId.brandId}
    , 1
    , NOW()
)
